from flask import Flask, request, session, redirect, url_for
import xml.etree.ElementTree as ET

app = Flask(__name__)
app.secret_key = 'your_secret_key'

@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    # Receive SAML response from Identity Provider
    saml_response = request.form.get('SAMLResponse')
    
    if not saml_response:
        return "No SAML Response received", 400
    
    try:
        # Parse the SAML response XML
        root = ET.fromstring(saml_response)
        
        # Extract user attributes from Assertion elements
        assertion = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
        if assertion is None:
            return "No Assertion found in SAML response", 400
        
        subject = assertion.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Subject')
        name_id = subject.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID').text
        attributes = assertion.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute')
        
        # Create user session
        user_attributes = {attr.get('FriendlyName'): attr.find('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text for attr in attributes}
        session['user'] = {'name_id': name_id, **user_attributes}
        
        return redirect(url_for('home'))
    
    except ET.ParseError:
        return "Invalid SAML response XML", 400

@app.route('/')
def home():
    if 'user' in session:
        return f"Welcome, {session['user']['name_id']}!"
    else:
        return "You are not logged in"

if __name__ == '__main__':
    app.run(debug=True)